mapper.select:
SELECT e.id, e.equipment_name, e.location, e.status, e.description, e.image_url, e.purchase_date, e.type_code, et.type_name, e.equipment_no, e.create_time FROM fitness_equipment e LEFT JOIN fitness_equipment_type et ON e.type_code = et.type_code AND et.deleted = false WHERE e.deleted = false
AND e.equipment_name LIKE '%' || #{query.keyword} || '%'
AND e.status = #{query.status}
AND e.type_code = #{query.typeCode}
ORDER BY e.create_time DESC
